package media

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal/int/media"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type DevPortalMediaProxy struct {
	media.UnimplementedDevPortalMediaServer
	client media.DevPortalMediaClient
}

func init() {
	proxyutil.Register(&media.DevPortalMedia_ServiceDesc, NewDevPortalMediaProxy)
}
func NewDevPortalMediaProxy(cc grpc.ClientConnInterface) media.DevPortalMediaServer {
	return &DevPortalMediaProxy{client: media.NewDevPortalMediaClient(cc)}
}
func (p *DevPortalMediaProxy) UpdateAssetStatus(ctx context.Context, in *media.UpdateAssetStatusRequest) (*media.UpdateAssetStatusResponse, error) {
	return proxyutil.ProxyMethod[media.UpdateAssetStatusRequest, media.UpdateAssetStatusResponse](p.client.UpdateAssetStatus)(ctx, in)
}
